-- Official Saas-Fee/Saastal restaurant catalogue from Saas-Fee/Saastal Tourism Deskline POIs.
-- Source checked: 2026-06-19
-- Source URL: https://www.saas-fee.ch/de/kulinarik/restaurants/pois
-- This seed adds profiles and contact data only. It does not add menu prices.

create extension if not exists pgcrypto;

create table if not exists public.global_knowledge (
  id uuid primary key default gen_random_uuid(),
  category text not null default 'general',
  title text not null,
  content text not null,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists global_knowledge_active_idx
  on public.global_knowledge(is_active, category);

create table if not exists public.restaurant_contacts (
  id uuid primary key default gen_random_uuid(),
  restaurant_name text not null unique,
  whatsapp_phone text,
  phone text,
  email text,
  accepts_whatsapp_reservations boolean not null default true,
  reservation_notes text,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.restaurant_menus (
  id uuid primary key default gen_random_uuid(),
  restaurant_name text not null,
  location text,
  cuisine text,
  average_check_min_chf numeric(10, 2),
  average_check_max_chf numeric(10, 2),
  menu_category text not null,
  item_name text not null,
  description text,
  price_chf numeric(10, 2),
  price_text text,
  dietary_tags text,
  source_url text,
  source_updated_at date,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint restaurant_menus_unique_item unique (
    restaurant_name,
    menu_category,
    item_name
  )
);

with official_restaurants(
  restaurant_name,
  town,
  address,
  phone,
  email,
  website,
  cuisine,
  topics,
  description,
  source_url
) as (
  values
    ('Old Cinema Pub', 'Saas-Fee', 'Bielmattstrasse 3, 3906 Saas-Fee', '+41 79 265 15 33', 'info@oldcinemapub.com', 'https://www.oldcinemapub.com/', 'Après-Ski', 'Bar/Pub/Lounge, Bar-Restaurant, Après-Ski', 'Seit der Eröffnung im Oktober 2020 zählt das Old Cinema Pub zum festen Bestandteil des Nachtlebens in Saas-Fee. Neben verschiedensten Biersorten und feinsten Cocktails bietet das Old Cinema auch Theaterstücke, Live-Music und gelegentlich auch Konzerte an. Geniessen Sie Ihr Feierabend-Bier oder einen leckeren Cocktail bei uns in gemütlicher Atmosphäre.', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Alpina', 'Saas-Almagell', 'Furggstaldenweg 15, 3905 Saas-Almagell', '+41 27 957 24 43', 'info@bergrestaurant-alpina.ch', 'http://www.bergrestaurant-alpina.ch', 'Schweizer Küche, Italienische Küche, Saisonale Küche, Saveur du Valais / Walliser Köstlichkeiten, Regionale Küche, Hausmannskost', 'Berghütte/Bergrestaurant, Schweizer Küche, Nichtraucher-Lokalität, Italienische Küche, Angebot für Kinder, Gutbürgerliches Ambiente, Mittagstisch, Saisonale Küche, Saveur du Valais / Walliser Köstlichkeiten, Regionale Küche, Ausflugslokal, Hausmannskost', 'Schmackhafte Walliser Spezialitäten, währschafte Hausmannskost und internationale Topweine, sind nur ein paar Highlights aus der vielseitigen Wein- und Speisekarte.Dank unserem ideenreichen Küchenchef, kommen bei uns auf Wunsch auch Gourmetliebhaber voll auf Ihre Kosten.Testen Sie uns! Auf Anfrage bleibt das Restaurant auch Abends geöffnet.', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Bergrestaurant Spielboden', 'Saas-Fee', null, null, null, null, null, 'Berghütte/Bergrestaurant', 'Bedientes Bergrestaurant mit grosser Sonnenterrasse. Das Restaurant mit Sonnenterasse bietet von verschiedenen klassischen Gerichten über Fleisch und Gemüse bin hin zum Burger eine abwechslungsreiche Winter- und Frühlingskarte. Barbecues im Schnee und verschiedene Events am Abend sorgen für unvergessliche Augenblicke. Öffnungszeiten: Gemäss Fahrplan Saas-Fee - Spielboden (2. Sektion) Nützliche Infos:Bedientes Restaurant mit grosser Sonnenterrasse Murmeltiere füttern: Im Frühling und Sommer werden die Murmeltiere u…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Restaurant Saaser-Stube by Navigare', 'Saas-Fee', null, null, null, 'https://navigare-resorts.com/en/resorts/saas-fee/saaser-stube/', 'Glutenfreie Küche, Saveur du Valais / Walliser Köstlichkeiten, Regionale Küche, Vegetarische Küche, Après-Ski, Französische Küche, Vegane Küche, Internationale Küche', 'Bar-Restaurant, Rustikales Ambiente, Angebot für Kinder, Glutenfreie Küche, Saveur du Valais / Walliser Köstlichkeiten, Nichtraucher-Lokalität, Regionale Küche, Vegetarische Küche, Après-Ski, Französische Küche, Vegane Küche, Internationale Küche', 'Entdecken Sie die Saaser Stube by Navigare – Alpine Gemütlichkeit trifft auf erstklassige Kulinarik. Inmitten der atemberaubenden Berglandschaft von Saas-Fee bietet unser Restaurant eine einzigartige Kombination aus traditioneller Alpenküche und modernen Gourmet-Kreationen. Sind Sie bereit für eine neue Erfahrung? Ein Erlebnis, das ehrliche und authentische Küche mit internationalen Einflüssen verschmelzen lässt. Das stilvolle Interieur aus warmem Holz, gemütlichen Sitznischen und kunstvollen Glasfenstern lädt zum…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Boccalino', 'Saas-Fee', 'Dorfstrasse 50, Restaurant Boccalino , 3906 Saas-Fee', '+41 27 957 17 31', null, 'https://www.pizzeria-boccalino.ch/', 'Pizzeria, Italienische Küche', 'Pizzeria, Restaurant, Italienische Küche', 'Schweizer und Italienische Küche', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Hohsaashütte', 'Saas-Grund', null, null, null, 'https://www.hohsaas-bergrestaurant.ch/de', 'Regionale Küche, Schweizer Küche, Saveur du Valais / Walliser Köstlichkeiten', 'Ausflugsrestaurant, Berghütte/Bergrestaurant, Bergrestaurant, Regionale Küche, Schweizer Küche, Saveur du Valais / Walliser Köstlichkeiten, Angebot für Kinder', 'Modernes Bergrestaurant/hütte mit einer Sonnenterrasse, von der sie einen unvergesslichen Blick auf das Monte-Rosa-Massiv und weitere imposante Viertausender haben. Übernachtungsmöglichkeit.', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Steinbock Bar', 'Saas-Fee', 'Untere Dorfstrasse 62, 3906 Saas-Fee', '+41 27 957 27 47', 'welcome@steinbock-saas-fee.ch', 'http://www.steinbock-saas-fee.ch', null, 'Bar-Restaurant, Bar/Pub/Lounge', 'Gediegene Bar für Après Ski und zum Verweilen. Klassische und moderne Cocktails und Drinks, diverse Gin''s, regionale Weine und Bier. Im Sommer 2026 kann die STEINBOCK BAR exklusiv für deien privaten Event gebucht werden.', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Pit Stop Bar', 'Saas-Fee', 'Bergrest. Morenia, 3906 Saas-Fee', '+41 27 957 18 81', 'morenia@bluewin.ch', 'http://de-de.facebook.com/pages/pitStop/280438687302', null, 'Berghütte/Bergrestaurant', 'Spezialitäten: diverse Ciabattas, American Burger… Gemütliche Sonnenterrasse mit Liegestühlen mit direktem Blick zum Fun Park Akzeptierte Fremdwährungen: Euro Nur im Winter geöffnet und hier gemäss Fahrplan der Alpin Express-Bahn.', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Alphütte', 'Saas-Fee', 'Wildistrasse 72, 3906 Saas-Fee', '+41 27 957 05 05', 'info@alphutte.ch', 'http://www.alphutte.ch', 'Regionale Küche, Traditionelle Küche, Hausmannskost, Schweizer Küche', 'Bar-Restaurant, Regionale Küche, Rustikales Ambiente, Nichtraucher-Lokalität, Traditionelle Küche, Hausmannskost, Schweizer Küche, Mittagstisch', 'In fast unberührter Natur bietet die Alphütte die Möglichkeit, vom Alltag abzuschalten und im Hier und Jetzt zu leben. Stille und Authentizität mitten in der urtümlichen Bergwelt ist garantiert. Die frische Bergluft geniessen , umgeben von Gipfeln Bietet die Alphütte die richtige Einkehrmöglichkeit und sich von unserer Küche zu verkosten lassen. Warme Küche 11:00 bis 14:00 & 17:00 bis 21:00', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Vieux Chalet', 'Saas-Fee', 'Untere Dorfstrasse 30, 3906 Saas-Fee', '+41 27 957 28 92', 'info@vieux-chalet-saas-fee.ch', 'http://www.vieux-chalet-saas-fee.ch/', 'Saveur du Valais / Walliser Köstlichkeiten, Schweizer Küche, Traditionelle Küche', 'Restaurant, Bar/Pub/Lounge, Saveur du Valais / Walliser Köstlichkeiten, Rustikales Ambiente, Angebot für Kinder, Schweizer Küche, Traditionelle Küche, Nichtraucher-Lokalität', 'Das Vieux Chalet ist ein heimeliges und rustikales Restaurant im Walliser Stil. Das Vieux Chalet ist ein heimeliges und rustikales Restaurant im Walliser Stil. Unsere Spezialitäten: 20 verschiedene hausgemachte Käsefondues - Fleischfondue Bourguignonne & Chinoise - Fondueplausch - Raclette - Schokoladenfondue - erlesene Walliserweine. Die Raucherbar, welche komplett vom Restaurant abgetrennt ist, verfügt über W-Lan. Im übrigen werden dort alle grossen Sportanlässe über Teleclub und Ski Sport gezeigt. Im Sommer ver…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Restaurant Olympia', 'Saas-Almagell', null, null, null, null, 'Saisonale Küche, Glutenfreie Küche, Steak-House, Grillspezialitäten, Live-Musik/Konzerte, Schweizer Küche, Griechische Küche', 'Restaurant, Café-Restaurant, Angebot für Kinder, Saisonale Küche, Glutenfreie Küche, Mittagstisch, Steak-House, Grillspezialitäten, Sonnenterrasse, Live-Musik/Konzerte, Tischreservierung möglich, Schweizer Küche, Griechische Küche', 'Feuer & Genuss im SaastalErleben Sie kulinarische Highlights: Grillspezialitäten und zartes Fleisch auf heissem Stein, saftige Burger und mehr!', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Nesti''s Ski- Bar', 'Saas-Fee', 'Dorfstrasse 17, 3906 Saas-Fee', '+41 27 957 42 11', null, null, 'Après-Ski', 'Bar/Pub/Lounge, Après-Ski, Ausflugslokal', 'Spezialitäten: Aprés-Ski Bar mit div. alkoholische und alkoholfreie Getränke, Long Drinks, Cocktails, div. Shots und Snacks. täglich geöffnet von 17.00 Uhr bis 1.30 Uhr', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Essstube Saas-Fee', 'Saas-Fee', 'Hannigstrasse 47, 3906 Saas-Fee', '+41 27 957 00 22', 'info@essstube.ch', 'https://www.essstube.ch/saas-fee-essstube.html', 'Bioküche, Vegetarische Küche, Saisonale Küche, Grillspezialitäten, Weizenfreie Küche, Traditionelle Küche, Vegane Küche, Schweizer Küche', 'Restaurant, Bioküche, Vegetarische Küche, Mittagstisch, Saisonale Küche, Grillspezialitäten, Weizenfreie Küche, Traditionelle Küche, Angebot für Kinder, Vegane Küche, Schweizer Küche', 'Restaurant mit Charakter und persönlichem Charme, sowohl in der Gestaltung der Atmosphäre, als auch in der Zubereitung der Speisen. Molekulare Elemente frischen traditionelle Gerichte auf und verhelfen so zu einem neuen Stil. Das Menü bietet die ideale Plattform für alle Bedürfnisse an einem Tisch, Salate,feine Suppen, Pasta, Wok-Gerichte Grillspezialitäten, Klassiker, Süsses- all das wird in der ESSSTUBE mit der Leib und Seele präsentiert und gekocht. Im Sommer lockt die Sonnenterasse vor dem Haus zum Entspannen…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Restaurant Alpenblick', 'Saas-Fee', 'Hohneggweg 100, 3906 Saas-Fee', '+41 76 539 32 78', 'info@alpenblick-saasfee.ch', 'http://www.alpenblick-saasfee.ch', 'Regionale Küche, Schweizer Küche', 'Bergrestaurant, Restaurant, Ausflugsrestaurant, Regionale Küche, Angebot für Kinder, Schweizer Küche, Gutbürgerliches Ambiente, Ausflugslokal', 'Neu renoviertes Ausflugsrestaurant mit fantastischer Aussicht auf die umliegende Gletscherwelt. Serviert werdenhausgemachte schweizerische Köstlichkeiten in einem gemütlichen Ambiente. am Abend offen für Veranstaltungen und Gruppen', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('DA RASSO', 'Saas-Fee', 'Obere Dorfstrasse 46, 3906 Saas-Fee', '+41 27 957 15 26', 'office@da-rasso.ch', 'http://www.da-rasso.ch', 'Pizzeria, Saisonale Küche, Italienische Küche, Vegetarische Küche', 'Café-Restaurant, Restaurant, Pizzeria, Saisonale Küche, Italienische Küche, Mittagstisch, Vegetarische Küche, Tischreservierung möglich, Drive-In/Take-Away', '✓ einmalige Sonnenterrasse mit atemberaubenden Blick auf die 4''000er✓ Pizza & saisonale Gerichte - leicht und trendy✓ gemütliches Ambiente in heller Architektur ✓ modern, im Zentrum von Saas-Fee', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Weissmieshütte', 'Saas-Grund', 'Innere Saastalstrasse 22, 3910 Saas-Grund', '+41 27 957 25 54', 'huette@weissmieshuette.ch', 'http://www.weissmieshuette.ch', 'Schweizer Küche, Regionale Küche, Saveur du Valais / Walliser Köstlichkeiten, Hausmannskost', 'Berghütte/Bergrestaurant, Bergrestaurant, Ausflugsrestaurant, Schweizer Küche, Ausflugslokal, Regionale Küche, Nichtraucher-Lokalität, Saveur du Valais / Walliser Köstlichkeiten, Rustikales Ambiente, Hausmannskost', 'Die Weissmieshütte der SAC Sektion Olten liegt auf 2726 Meter über Meer auf einer Sonnenterrasse oberhalb von Saas Grund und ist mit dem Panoramablick auf 18 Viertausender eine der am schönsten gelegenen Berghütten im Wallis. Sie ist der Ausgangspunkt für die Viertausender Weissmies und Lagginhorn, den Beinahe-Viertausender Fletschhorn, die Sportkletterrouten in der Jegihorn-Südwand, den höchst gelegenen Klettersteig der Alpen, den Gsponer Höhenweg sowie zahlreiche Ski- und Snowboard-Touren. Die Hütte ist von der…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Bergrestaurant Kreuzboden', 'Saas-Grund', null, null, null, null, null, 'Ausflugsrestaurant, Berghütte/Bergrestaurant', 'Kreuzboden oberhalb von Saas Grund – mit der Gondelbahn bequem erreichbar – ist nicht nur DER Treff für Familien, Wanderer und Biker: Auf der Sonnenterrasse des Bergrestaurants lässt sich auch der Ausblick auf die imposante Mischabelgruppe ganz besonders geniessen. Öffnungszeiten gemäss Fahrplan der Kreuzboden-Gondelbahn', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Bergrestaurant Gletschergrotte', 'Saas-Fee', 'Wildistrasse 59, 3906 Saas-Fee', '+41 27 957 21 60', 'info@gletschergrotte.ch', 'http://www.gletschergrotte.ch', 'Saveur du Valais / Walliser Köstlichkeiten, Saisonale Küche, Traditionelle Küche, Mediterrane Küche, Hausmannskost, Regionale Küche, Schweizer Küche, Après-Ski', 'Café-Restaurant, Restaurant, Bergrestaurant, Ausflugsrestaurant, Berghütte/Bergrestaurant, Saveur du Valais / Walliser Köstlichkeiten, Saisonale Küche, Traditionelle Küche, Gutbürgerliches Ambiente, Mediterrane Küche, Hausmannskost, Regionale Küche, Schweizer Küche, Ausflugslokal, Nichtraucher-Lokalität, Après-Ski, Rustikales Ambiente, Glutenfreie Küche, Vegetarische Küche, Angebot für Kinder', 'Das gemütliche Bergrestaurant mit einer wunderschönen Sonnenterrasse Bergrestaurant Gletschergrotte, auch genannt ‚z Gröttli‘ Das gemütliche, bediente Restaurant, familiär und persönlich geführt, überzeugt mit seinem Bergcharme, freundlichem Personal und schöner Sonnenterrasse zum entspannen und verweilen. Geniessen Sie typische Schweizer Küche kombiniert mit feinen saisonalen Leckereien sowie das Kuchenbuffet mit feinen selbstgebackenen Köstlichkeiten. Es wird Wert gelegt auf frische und selbstgemachte Produkte.…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Restaurant Pirmin Zurbriggen', 'Saas-Almagell', 'Furusandstrasse 16, 3905 Saas-Almagell', '+41 27 957 23 01', 'info@wellnesshotel-zurbriggen.ch', 'http://www.wellnesshotel-zurbriggen.ch/', 'Französische Küche, Nouvelle Cuisine', 'Restaurant, Nichtraucher-Lokalität, Französische Küche, Gehobenes Ambiente, Nouvelle Cuisine, Modernes Ambiente, Tischreservierung möglich, Luxus-Ambiente', 'Geniessen Sie das feine Essen im einzigartigen Speisesaal Art Heinz Julen. Koch Markus Ries. 5-Gang Wahl-Abendessen für CHF 55.-- pro Person. Reservation unter 027 957 23 01 erforderlich!', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Tea-Room Rest. Saaser Bäckerei', 'Saas-Grund', 'Saastalstrasse 247, 3910 Saas-Grund', '+41 27 957 29 02', 'saaser-baeckerei@bluewin.ch', null, 'Kaffeehaus/Konditorei, Schweizer Küche, Saveur du Valais / Walliser Köstlichkeiten', 'Kaffeehaus/Konditorei, Tea-Room/Café, Drive-In/Take-Away, Schweizer Küche, Saveur du Valais / Walliser Köstlichkeiten', 'WALLISERROGGENBROT IN DIVERSE VARIANTEN, HAUSGEMACHTE PRALINÉS UND SCHOKOLADE, FEINE BAUMNUSSTORTEN NACH GEHEIMREZEPT, DIVERSE BROT SPEZIALITÄTEN, HAUSGEMACHTES EIS, KONFISERIE UND PATISSERIE WAREN. AUSFEINSTEN ZUTATEN ENTSTEHEN BELIEBTE SPEZIALITÄTEN. SEIT 1972 SIE MÖCHTEN EIN PAAR TAGEN IM SAASTAL BLEIBEN ? KEIN PROBLEM; WIR BIETEN AUCH BED & BREAKFAST AN Een lekker kopje koffie met een gebakje, een pilsje, een wijntje, een lekker belegd broodje; U kunt het allemaal bij ons bestellen. Lekker genieten in de Tearo…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Restaurant Walliserkanne', 'Saas-Fee', 'Lomattenstrasse 7, 3906 Saas-Fee', '+41 27 958 10 00', 'info@allalin.ch', 'https://allalin.ch/dining/', 'Saisonale Küche, Vegetarische Küche, Schweizer Küche, Regionale Küche, Saveur du Valais / Walliser Köstlichkeiten, Internationale Küche', 'Bar-Restaurant, Restaurant, Saisonale Küche, Vegetarische Küche, Gutbürgerliches Ambiente, Schweizer Küche, Angebot für Kinder, Regionale Küche, Saveur du Valais / Walliser Köstlichkeiten, Internationale Küche, Nichtraucher-Lokalität, Rustikales Ambiente', 'Täglich wechselnde creative Menus und kleines à la carte Angebot in gemütlichem Ambiente Verbringen Sie entspannte Stunden im Restaurant Walliserkanne wo Sie bei Kerzenlicht umgeben von 350-jährigem Lärchenholz leichte und marktfrische Gerichte speisen können. Die Gestaltung des Restaurants sowie der kulinarischen Kreationen sind mit Liebezum Detail vollendet. Unser Küchenteam wird Sie mit kreativen Köstlichkeiten verwöhnen. Unsere Gäste werden abends mit eineminnovativen Füng-Gänge-Menü mit tollem Salatbuffet und…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Restaurant Mattmark am Stausee', 'Saas-Almagell', 'Mattmark Stausee, 3905 Saas Almagell', '+41 78 262 88 41', 'mattmark2200@gmail.com', null, 'Vegetarische Küche, Regionale Küche, Traditionelle Küche, Hausmannskost, Eigene Weine/landwirtsch. Produkte, Schweizer Küche, Saveur du Valais / Walliser Köstlichkeiten', 'Restaurant, Bergrestaurant, Ausflugsrestaurant, Vegetarische Küche, Regionale Küche, Ausflugslokal, Traditionelle Küche, Hausmannskost, Eigene Weine/landwirtsch. Produkte, Rustikales Ambiente, Gutbürgerliches Ambiente, Schweizer Küche, Mittagstisch, Saveur du Valais / Walliser Köstlichkeiten', 'Die Terrasse bietet einen atemberaubenden Blick auf den Stausee und den Monte Moro Pass. Saisonende 31.10.2026', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Cäsar Ritz', 'Saas-Fee', 'Dorfweg 1, 3906 Saas-Fee', '+41 27 958 19 00', 'info@walliserhof-saasfee.ch', 'http://walliserhof-saasfee.ch', 'Schweizer Küche, Gault-Millau, Vegetarische Küche, Regionale Küche, Vegane Küche, Saisonale Küche', 'Restaurant, Schweizer Küche, Nichtraucher-Lokalität, Gault-Millau, Vegetarische Küche, Regionale Küche, Vegane Küche, Saisonale Küche, Modernes Ambiente', 'Entdecken Sie Gourmet-Küche auf höchstem Niveau, ausgezeichnet mit 14 Punkten von Gault Millau. Unser Chef Jakub Baron und sein Team freuen sich, Sie verwöhnen zu dürfen. Reservieren Sie einen Tisch bequem online: https://www.walliserhof-saasfee.ch/restaurant-reservation Regional. Saisonal. Ab und zu auch international. Unser Küchenteam verwöhnt Sie mit einem einzigartigen Zusammenspiel von besten regionalen sowie saisonalen Produkten und innovativem Kochhandwerk. Regional. Saisonal. Ab und zu auch international.…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Cafe Miska', 'Saas-Fee', 'Obere Dofstrasse 60, 3906 Saas-Fee', '+41 768609863', 'info@cafemiska.ch', null, 'Bioküche', 'Café-Restaurant, Angebot für Kinder, Kinderstühle, Drive-In/Take-Away, Modernes Ambiente, Kinderecke, Bioküche', 'Wir bieten Ihnen eine grosse Auswahl an Snacks und Getränken. Unser Café hat eine Kinderecke und Hunde sind herzlich willkommen.', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Restaurant 1659', 'Saas-Almagell', 'Talstrasse 43, 3905 Saas Almagell', '+41 27 958 17 00', 'kristall@kristall.ch', 'http://www.kristall.ch', 'Qualitäts-Label Q I, Saisonale Küche, Schweizer Küche, Französische Küche, Saveur du Valais / Walliser Köstlichkeiten, Regionale Küche, Vegetarische Küche, Italienische Küche', 'Restaurant, Qualitäts-Label Q I, Ausflugslokal, Saisonale Küche, Schweizer Küche, Französische Küche, Saveur du Valais / Walliser Köstlichkeiten, Regionale Küche, Vegetarische Küche, Angebot für Kinder, Italienische Küche', 'GeniessenSie unsere kulinarische Küche mit typischen Schweizergerichten sowiefranzösischen und italienischen Speisen. Für dieZubereitung der Gerichte verwenden wir vorwiegend heimische Produkte wieKalbfleisch und Alpkäse aus der eigenen Landwirtschaft, Gemüse aus demHausgarten, hausgemachte Butter, sowie im Sommer Forellen aus dem eigenenFelsenteich. Währendden sonnigen Tagen lädt tagsüber unser Gartenrestaurant zum Verweilen undGeniessen ein. Abends verwöhnen wir Siein unserem Speisesaal bzw. Restaurant.', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
