    ('Tankstell', 'Saas-Fee', 'Hügelweg 3, 3906 Saas-Fee', '+41 78 246 66 37', 'hallo@tankstell-saas-fee.ch', 'www.tankstell-saas-fee.ch', 'Catering/Party-Service, Glutenfreie Küche, Italienische Küche, Mediterrane Küche, Weinprobe/-verkostung/-verkauf, Geschlossene Gesellschaft möglich, SB/Selbstbedienung', 'Café-Restaurant, Restaurant, Catering/Party-Service, Glutenfreie Küche, Tischreservierung möglich, Sonnenterrasse, Italienische Küche, Mediterrane Küche, Weinprobe/-verkostung/-verkauf, Kinderstühle, Angebot für Kinder, Drive-In/Take-Away, Geschlossene Gesellschaft möglich, Modernes Ambiente, SB/Selbstbedienung', 'Mit frischen Aromen aus der Region und viel Liebe zum Handwerk servieren wir täglich frisch hergestellte Pasta mit herzhaften Saucen, Arve, Eringer-Rind, Roggenbrot, Wild und saisonales Gemüse. Aktuell befinden wir uns in der Saisonpause. Gerne sind wir ab dem 19.06.2026 wieder für euch da und freuen uns auf einen sonnigen Sommer in Saas Fee. Euer Team Tankstell', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('12-inch CofFee', 'Saas-Fee', 'Untere Dorfstrasse 42, 3906 Saas-Fee', '+41 27 957 12 85', 'info@12inch.coffee', 'http://www.12inch.coffee', 'Kaffeehaus/Konditorei', 'Kaffeehaus/Konditorei, Tea-Room/Café, Café-Restaurant, Internetcafé, Nichtraucher-Lokalität, Drive-In/Take-Away, Modernes Ambiente', 'Die urbane Coffee & Vinyl Bar im Herzen Saas-Fees Die urbarne Kaffeebar im Herzen Saas-Fees. Hier lässtsich gemütlich Kaffeetrinken! Es gibt original französische Frühstücks-Croissants, belegte Bagels, feine Kuchen und herzhafte Kleinigkeiten. Ausgewählte Wein- und Bierspezialitäten runden das Angebot ab. Dazu geniessen unsere Gäste besteMusik nicht nur digital, ab und an auch vom Plattenteller! Täglich von 09:00 bis 19:00 Uhr können sich unsere Gäste neben dem eigens gerösteten Specialty Coffee auch über trendige…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Drehrestaurant Allalin', 'Saas-Fee', '3906 Saas-Fee', '+41 79 263 71 82', 'drehrestaurant@saas-fee.ch', 'https://www.saas-fee.ch/de/kulinarik/bergrestaurants/drehrestaurant-allalin?gad_', null, 'Berghütte/Bergrestaurant', 'Das höchstgelegene Drehrestaurant der Welt auf 3500 m ü. M. Nur eines macht noch mehr Freude als die leckere Küche: der einzigartige Ausblick auf unzählige Bergriesen. In einer Stunde dreht sich das Restaurant um 360 Grad um die eigene Achse. Während Sie regionale und internationale Speisen geniessen, können Sie sich an der ständig wechselnden Aussicht sattsehen.', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Fee Bistro', 'Saas-Fee', 'Untere Dorfstrasse 64, 3906 Saas-Fee', null, 'info@feepub-saasfee.ch', 'https://feepub-saasfee.ch/fee-pub-2', 'Bistro', 'Bistro', 'Ein gemütlicher Treffpunkt für Genießer – bei uns erwarten dich aromatischer Kaffee, feine Apéros und kleine, liebevoll zubereitete Snacks. In entspannter Atmosphäre lässt es sich wunderbar verweilen, plaudern und den Alltag für einen Moment vergessen', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Bergrestaurant Heidbodme', 'Saas-Almagell', '3905 Saas-Almagell', '+41 27 957 23 26', 'bergbahnen-almagell@bluewin.ch', null, null, 'Berghütte/Bergrestaurant', 'Geniessen Sie das Panorama auf die Monta-Rosa-Kette mit dem höchsten Grenzberg der Schweiz, die Dufour-Spitze sowie auf das imposante Strahlhorn, dann folgt der Egginer, das Mittaghorn und im Nord-Westen erblickt man die Ausläufer der Mischabelkette. Anschliessend werfen Sie einen Blick nach Süd-Osten ins langgezogene Furggtal Richtung Antronapass (2''838 m).', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('La Ferme', 'Saas-Fee', 'Obere Dorfstrasse 30, 3906 Saas-Fee', null, 'info@laferme-sf.ch', null, 'Slowfood, Vegetarische Küche, Saveur du Valais / Walliser Köstlichkeiten, Hausmannskost, Eigene Weine/landwirtsch. Produkte, Geschlossene Gesellschaft möglich, Fait Maison, Weinprobe/-verkostung/-verkauf', 'Bar-Restaurant, Slowfood, Nichtraucher-Lokalität, Vegetarische Küche, Sonnenterrasse, Saveur du Valais / Walliser Köstlichkeiten, Angebot für Kinder, Hausmannskost, Eigene Weine/landwirtsch. Produkte, Geschlossene Gesellschaft möglich, Fait Maison, Tischreservierung möglich, Weinprobe/-verkostung/-verkauf, Traditionelle Küche, Saisonale Küche, Schweizer Küche', 'Eine raffinierte Alpenbrasserie, die Schweizer und Walliser Zutaten zelebriert und sich von der kulinarischen Tradition der umliegenden Alpenregionen inspirieren lässt. Saisonale Produkte, lokale Aromen und gemütliche Chalet‑Atmosphäre verbinden sich mit zurückhaltender Eleganz für entspannte Mittagessen und stimmungsvolle Abendessen.​ Une brasserie alpine raffinée mettant à l''honneur les produits suisses et valaisans, inspirée par le patrimoine culinaire des régions alpines voisines. Produits de saison, saveurs l…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('Restaurant Pizzeria Channa', 'Saas-Almagell', 'Platzweg 10, 3905 Saas-Almagell', '+41 27 957 26 21', 'channa@bayard-art.ch', 'http://www.bayard-art.ch', 'Pizzeria, Après-Ski, Saveur du Valais / Walliser Köstlichkeiten, Italienische Küche, Regionale Küche', 'Restaurant, Pizzeria, Schneebar, Nichtraucher-Lokalität, Drive-In/Take-Away, Après-Ski, Saveur du Valais / Walliser Köstlichkeiten, Italienische Küche, Regionale Küche, Mittagstisch, Angebot für Kinder', 'Das neurestaurierte Restaurant-Pizzeria mit gemütlichen Ambiente bietet gute regionale Küche, sowie Pizza aus dem Holzofen. Sonnenterrasse, kleiner Kinderspielplatz. Im Winter Schneebar.', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois'),
    ('The Larix', 'Saas-Fee', 'Gletscherstrasse 14, 3906 Saas-Fee', '+41 27 958 64 64', 'info@the-larix.ch', 'https://www.the-larix.ch', 'Fischküche, Italienische Küche', 'Restaurant, Fischküche, Italienische Küche', 'Das Restaurant The Larix wurde im Herbst 2015 renoviert. Der moderne und gemütliche Chalet-Style lädt zum Verweilen ein. Die Italienische Küche bietet für jeden Geschmack genau das Richtige und jeder Wunsch wird nach Möglichkeit erfüllt. Ob Pasta, Fisch oder weitere Köstlichkeiten aus Italien – Wir erwarten Sie gerne bei uns. Wir freuen uns, Ihnen eine besondere Neuigkeit mitteilen zu können: Das Restaurant "i due amici" by The Larix hat nun im The Larix Hotel eröffnet. Entstanden aus der Freundschaft und Leidensc…', 'https://www.saas-fee.ch/de/kulinarik/restaurants/pois')
),
contact_upsert as (
  insert into public.restaurant_contacts (
    restaurant_name,
    whatsapp_phone,
    phone,
    email,
    accepts_whatsapp_reservations,
    reservation_notes,
    is_active,
    updated_at
  )
  select
    restaurant_name,
    null,
    phone,
    email,
    false,
    'Official Saas-Fee/Saastal restaurant contact imported from Deskline POI catalogue on 2026-06-19. WhatsApp reservation sending is disabled until a WhatsApp-enabled number is verified for this restaurant.',
    true,
    now()
  from official_restaurants
  on conflict (restaurant_name) do update set
    phone = coalesce(nullif(excluded.phone, ''), public.restaurant_contacts.phone),
    email = coalesce(nullif(excluded.email, ''), public.restaurant_contacts.email),
    whatsapp_phone = public.restaurant_contacts.whatsapp_phone,
    accepts_whatsapp_reservations = case
      when public.restaurant_contacts.whatsapp_phone is not null
        and public.restaurant_contacts.whatsapp_phone <> ''
      then public.restaurant_contacts.accepts_whatsapp_reservations
      else false
    end,
    reservation_notes = case
      when public.restaurant_contacts.whatsapp_phone is not null
        and public.restaurant_contacts.whatsapp_phone <> ''
      then public.restaurant_contacts.reservation_notes
      else excluded.reservation_notes
    end,
    is_active = true,
    updated_at = now()
  returning restaurant_name
),
menu_upsert as (
  insert into public.restaurant_menus (
    restaurant_name,
    location,
    cuisine,
    average_check_min_chf,
    average_check_max_chf,
    menu_category,
    item_name,
    description,
    price_chf,
    price_text,
    dietary_tags,
    source_url,
    source_updated_at,
    is_active,
    updated_at
  )
  select
    restaurant_name,
    concat_ws(', ', nullif(address, ''), nullif(town, '')),
    nullif(cuisine, ''),
    null::numeric,
    null::numeric,
    'official_profile',
    'Official restaurant profile',
    concat_ws(' ', nullif(description, ''), 'Topics: ' || topics),
    null::numeric,
    'Current menu prices are not stored in the chat data for this restaurant yet.',
    null,
    source_url,
    '2026-06-19'::date,
    true,
    now()
  from official_restaurants
  on conflict (restaurant_name, menu_category, item_name) do update set
    location = excluded.location,
    cuisine = excluded.cuisine,
    description = excluded.description,
    price_chf = null,
    price_text = excluded.price_text,
    source_url = excluded.source_url,
    source_updated_at = excluded.source_updated_at,
    is_active = true,
    updated_at = now()
  returning restaurant_name
)
delete from public.global_knowledge
where category = 'restaurants'
  and title = 'Official Saas-Fee/Saastal restaurant directory';

